void function_host_init(void) {
    /* this groups all the initialisation stuff that was floating around the .h file */

    //sockets_accept sets newsocket to new sockets id and waits till user sets
    //newsocket=INVALID_SOCKET before accepting new sockets
    //shared global variables
    newsocket = INVALID_SOCKET;
    newsocket_ip = 0;
    //temp local variables (transferred to globals after successful connection)
    tnewsocket = INVALID_SOCKET;
    tnewsocket_ip = 0;
    hsockets_accept = NULL;
    idsockets_accept = NULL;

    AUTOPICKUPfirst = 0;
    AUTOPICKUPnextfree = 0;
    housestorageadd = 0;
    housestoragerestore = 0; //flags used when saving/restoring house items in file
    //house creation tool 1.0 variables
    patchx = 0;
    patchy = 0; //base offset for adding objects/changing basetiles
    housenumber = 65535; //house currently being created (1-?, 0 RESERVED, 65535=non-specific)
    basehousenumber = 20;

    //OBJadd_allow=FALSE;
    OBJmove_allow = FALSE;
    OBJlist_last = 0;

    //entry values
    WPF_NEXTTO = 0;
    WPF_OBJECT = NULL;
    objsave_last = -1;
    objsave_node_last = -1;

    hrevive_infiniteloopexit = NULL;
    idrevive_infiniteloopexit = NULL;
    stealing_txt = NULL;
    stealing_MESSAGE = TRUE;
    OBJtmp = NULL;
    OBJtmp2 = NULL;
    OBJtmp3 = NULL;
    OBJaddtocontainer_containermore = NULL;
}


void AUTOPICKUPadd(object *partymember, object *obj) {
    //adds an item to the autopickup list
    static npc *tnpc;
    tnpc = (npc *) partymember->more;
    AUTOPICKUPobject[AUTOPICKUPnextfree] = obj;
    AUTOPICKUPett[AUTOPICKUPnextfree] = ett;
    AUTOPICKUPplayer[AUTOPICKUPnextfree] = tnpc->player;
    AUTOPICKUPpartymember[AUTOPICKUPnextfree] = partymember;
    AUTOPICKUPflags[AUTOPICKUPnextfree] = 0;
    if (obj->info & 32768) {
        //remove mark if present and flag correctly
        obj->info ^= 32768;
        AUTOPICKUPflags[AUTOPICKUPnextfree] |= 1;
    }
    AUTOPICKUPnextfree++;
    if (AUTOPICKUPnextfree == AUTOPICKUPfirst) {
        AUTOPICKUPfirst++;
    }
AUTOPICKUPadd_selfmanagement:
    if (AUTOPICKUPfirst != AUTOPICKUPnextfree) {
        if (AUTOPICKUPett[AUTOPICKUPfirst] < (ett - 1024.0f)) {
            AUTOPICKUPfirst++;
            goto AUTOPICKUPadd_selfmanagement;
        }
    }
} //AUTOPICKUPadd

object *AUTOPICKUPcheck(player *tplayer, object *obj) {
    //returns an object pointer to the npc to return the item to or NULL
    static short i, i2;
AUTOPICKUPcheck_selfmanagement:
    if (AUTOPICKUPfirst != AUTOPICKUPnextfree) {
        if (AUTOPICKUPett[AUTOPICKUPfirst] < (ett - 1024.0f)) {
            AUTOPICKUPfirst++;
            goto AUTOPICKUPcheck_selfmanagement;
        }
    }
    i = AUTOPICKUPfirst;
AUTOPICKUPcheck_next:
    if (i != AUTOPICKUPnextfree) {
        if (AUTOPICKUPobject[i] == obj) {
            if (AUTOPICKUPplayer[i] == tplayer) {
                for (i2 = 0; i2 <= 7; i2++) {
                    if (AUTOPICKUPpartymember[i] == tplayer->party[i2]) {
                        AUTOPICKUPobject[i] = NULL; //set object as invalid
                        AUTOPICKUPett[i] = ett - 1024.0f - 1.0f; //set ett so object can easily be cleared
                        if (AUTOPICKUPflags[i] & 1) {
                            obj->info |= 32768;
                        }
                        return AUTOPICKUPpartymember[i];
                    }
                } //i2
                return NULL;
            }
        }
        i++;
        goto AUTOPICKUPcheck_next;
    }
    return NULL;
} //AUTOPICKUPcheck


DWORD WINAPI sockets_accept(LPVOID null_value) {
    static long x;
sockets_accept_next:
    static sockaddr_in accept_addr;
    ZeroMemory(&accept_addr, sizeof(accept_addr));
    x = sizeof(accept_addr);
    tnewsocket = accept(u6osocket, (sockaddr *) &accept_addr, (int *) &x);
    tnewsocket_ip = NULL;
    if (accept_addr.sin_family == AF_INET) {
        tnewsocket_ip = accept_addr.sin_addr.s_addr;
    }

    //ban by IP?
    static file *tfh;
    static txt *t = txtnew(), *t2 = txtnew();
    tfh = open2("banip.txt", OF_READWRITE | OF_SHARE_COMPAT);
    if (tfh->h != HFILE_ERROR) {
    banip_nextip:
        if (seek(tfh) < lof(tfh)) {
            txtfilein(t, tfh);
            if (t->l) {
                txtset(t2, t);
                x = (long) txtnum(t);
            banip_nextbyte1:
                txtright(t, t->l - 1);
                if (t->d2[0] != 46) goto banip_nextbyte1;
                txtright(t, t->l - 1);
                x += ((long) txtnum(t) << 8);
            banip_nextbyte2:
                txtright(t, t->l - 1);
                if (t->d2[0] != 46) goto banip_nextbyte2;
                txtright(t, t->l - 1);
                x += ((long) txtnum(t) << 16);
            banip_nextbyte3:
                txtright(t, t->l - 1);
                if (t->d2[0] != 46) goto banip_nextbyte3;
                txtright(t, t->l - 1);
                x += ((long) txtnum(t) << 24);
                if (tnewsocket_ip == x) {
                    x = tnewsocket;
                    txtset(t, "BannedIP_Blocked:");
                    txtadd(t, t2);
                    LOGadd(t); //log
                    shutdown(x, SD_RECEIVE | SD_SEND);
                    SleepEx(4096, NULL);
                    closesocket(x);
                    goto sockets_accept_next;
                } //tnewsocket_ip==x
            } //t->l
            goto banip_nextip;
        }
        close(tfh);
    } //!=HFILE_ERROR


    x = 1;
    setsockopt(tnewsocket, IPPROTO_TCP, TCP_NODELAY, (char *) &x, 4);
    x = 65536;
    setsockopt(tnewsocket, SOL_SOCKET, SO_RCVBUF, (char *) &x, 4);
    x = 65536;
    setsockopt(tnewsocket, SOL_SOCKET, SO_SNDBUF, (char *) &x, 4);
    x = 1;
    ioctlsocket(tnewsocket, FIONBIO, (unsigned long *) &x);


    //WSAAsyncSelect(newsocket, hWnd, WM_USER + 100, FD_READ | FD_WRITE | FD_CONNECT);

    /*
  timeval tv_r;
  tv_r.tv_sec = 0;
  tv_r.tv_usec = 500;
  fd_set socketset;
  FD_ZERO(&socketset);
  FD_SET(newsocket, &socketset);
  select(FD_SETSIZE, &socketset, NULL, NULL, &tv_r);
  */

    //x=1; ioctlsocket(newsocket, FIONBIO, (u_long FAR*) &x);

    //x=0; setsockopt(newsocket,SOL_SOCKET,SO_DONTLINGER,(char*)&x,4);

    send(tnewsocket, (char *) &U6O_SIGNATURE, 4, 0);

    newsocket_ip = tnewsocket_ip;
    newsocket = tnewsocket;
newsocket_wait:
    if (newsocket != INVALID_SOCKET) {
        SleepEx(15, FALSE);
        goto newsocket_wait;
    }
    goto sockets_accept_next;
    ExitThread(0);
    return 0;
}


/*
//volatile links (vlnk)
*/

void VLNKnew(void *lnks, void *lnk, unsigned long off) {
    if (vlnkb_free_last == -1) {
        vlnkb_off[++vlnkb_last] = off;
        vlnkb_lnk[vlnkb_last] = lnk;
        vlnkb_lnks[vlnkb_last] = lnks;
    } else {
        vlnkb_off[vlnkb_free[vlnkb_free_last]] = off;
        vlnkb_lnk[vlnkb_free[vlnkb_free_last]] = lnk;
        vlnkb_lnks[vlnkb_free[vlnkb_free_last--]] = lnks;
    }
}

void VLNKremove(void *lnk) {
    //remove any vlnk to lnk from other object
    //if (lnk==NULL) MessageBox(NULL,"NULL/removed vlnk","Ultima 6 Online",MB_OK);
    static long i;
    static unsigned long *lp;
    for (i = 0; i <= vlnkb_last; i++) {
        if (vlnkb_lnk[i] == lnk) {
            lp = (unsigned long *) vlnkb_off[i];
            lp[0] = NULL; //NULL vlnk
            vlnkb_lnk[i] = NULL;
            vlnkb_lnks[i] = NULL;
            vlnkb_off[i] = NULL; //remove vlnk
            vlnkb_free[++vlnkb_free_last] = i;
        } //=
    } //i
}

void VLNKsremove(void *lnks) {
    //remove all vlnk using offset within lnks
    static long i;
    for (i = 0; i <= vlnkb_last; i++) {
        if (vlnkb_lnks[i] == lnks) {
            vlnkb_lnk[i] = NULL;
            vlnkb_lnks[i] = NULL;
            vlnkb_off[i] = NULL; //remove vlnk
            vlnkb_free[++vlnkb_free_last] = i;
        } //=
    } //i
}

object *OBJnew() {
    if (objb_free_last == -1) {
        //if (objb_last>28039) MessageBox(NULL,"OBJnew","Ultima 6 Online",MB_OK);

        //objb_last+=10000;
        ZeroMemory(&objb[++objb_last], sizeof(object));
        return &objb[objb_last];
    } else {
        ZeroMemory(&objb[objb_free[objb_free_last]], sizeof(object));
        return &objb[objb_free[objb_free_last--]];
    }
    return NULL; //OBJnew failed
}


void OBJrelease(object *obj) {
    int i = 0;
    //all objects attached to primary object must also be released
    objb_free[++objb_free_last] = ((unsigned long) obj - (unsigned long) &objb) / sizeof(object);
    //for debugging "double release object bug"
    /*for(i=0;i<objb_free_last-1;i++) {
    if(objb_free[objb_free_last]==objb_free[i]) {
      i=objb_free_last;
    }
  }*/
    //clear object data
    ZeroMemory(obj, sizeof(object));
}

/* free player struct */
void free(player *plr) {
    static unsigned int i;
    for (i = 0; i <= 9; i++) {
        VLNKremove(plr->ktar[i]);
        VLNKsremove(plr->ktar[i]);
        OBJremove(plr->ktar[i]);
        OBJrelease(plr->ktar[i]);
    }
    VLNKremove(plr->talk_target);
    VLNKsremove(plr->talk_target);
    OBJremove(plr->talk_target);
    OBJrelease(plr->talk_target);
    free(plr->password);
    free(plr->name);
    free(plr->newpassword);
    if (plr->npcname) {
        /* this should be always set when the player logs in, but I'll add this here just in case */
        free(plr->npcname);
    }
    free((void *) plr);
}

/* free creature items and creature struct */
void free(creature *crt) {
    static unsigned int x5 = 0, y6;
    static object *myobj;
    //free inventory items
    myobj = (object *) crt->items; //includes the bag!
    if (myobj) x5 = OBJlist(myobj);
    OBJlist_last = NULL;
    for (y6 = 0; y6 < x5; y6++) {
        OBJremove(OBJlist_list[y6]);
        OBJrelease(OBJlist_list[y6]);
    }
    free((void *) crt);
}

/* this should properly clean everything from npc struct and after that free the struct,except the horse, because when removing npc it should be always dismounted*/
void free(npc *tnpc) {
    static unsigned int x5, x2, y6;
    static object *myobj;
    //free inventory items
    x5 = 0;
    for (x2 = 0; x2 <= 8; x2++) {
        if (x2 == 0) myobj = tnpc->helm;
        if (x2 == 1) myobj = tnpc->wep_right;
        if (x2 == 2) myobj = tnpc->wep_left;
        if (x2 == 3) myobj = tnpc->armour;
        if (x2 == 4) myobj = tnpc->boots;
        if (x2 == 5) myobj = tnpc->neck;
        if (x2 == 6) myobj = tnpc->ring_right;
        if (x2 == 7) myobj = tnpc->ring_left;
        if (x2 == 8) myobj = (object *) tnpc->items; //includes the bag!
        if (myobj) x5 = OBJlist(myobj);
    }
    OBJlist_last = NULL;
    for (y6 = 0; y6 < x5; y6++) {
        if ((OBJlist_list[y6]->type & 1023) == OBJ_HORSE_PAPERS) {
            /* if item being relesed is horse paper, remove the horse also */
            myobj = (object *) ((creature *) ((object *) OBJlist_list[y6]->more)->more)->more;
            OBJremove(myobj);
            OBJrelease(myobj);
            free((creature *) ((object *) OBJlist_list[y6]->more)->more);
            OBJremove((object *) OBJlist_list[y6]->more);
            OBJrelease((object *) OBJlist_list[y6]->more);
        } else if ((OBJlist_list[y6]->type & 1023) == OBJ_SHIP_DEED) {
            /* remove the ship */
            myobj = (object *) OBJlist_list[y6]->more;
            if ((myobj->type & 1023) == OBJ_SHIP) {
                //ship
                static mlobj *mmyobj;
                if (myobj->info & 2) {
                    /* If on board the ship */
                    tnpc = (npc *) myobj->more;
                    mmyobj = (mlobj *) tnpc->player->craft_con;
                } else {
                    mmyobj = (mlobj *) myobj->more;
                }
                for (x2 = 0; x2 <= 4; x2++) {
                    OBJremove(mmyobj->obj[x2]);
                    OBJrelease(mmyobj->obj[x2]);
                }
            }
            if (!(myobj->info & 2) && myobj->type != 0 && myobj->x != 0 && myobj->y != 0) {
                //remove the ship main object / skiff only if no one is abroad and the skiff is not already removed
                OBJremove(myobj);
                OBJrelease(myobj);
            }
        }
        OBJremove(OBJlist_list[y6]);
        OBJrelease(OBJlist_list[y6]);
    }
    free(tnpc->name);
    free((void *) tnpc);
}

void OBJcheckflags(unsigned long x, unsigned long y) {
    //bt[][] unsigned short
    //512 current basetiles exist ->expandable to 1024 using 10 bits
    //6 bit flags reamain
    //1=land passabe
    //2=air passable
    //4=sea passable
    //8=bolt passable
    //16=NPC passable (unlocked doors/containing items that can be picked up)
    //32=view OK (can be seen past)
    OBJcheckflags_flags = btflags[bt[y][x] & 1023]; //reset using basetile flags
    OBJcheckflags_flags += 32; //look ok
    if (((bt[y][x] & 1023) >= 140) && ((bt[y][x] & 1023) < 188)) OBJcheckflags_flags &= (255 - 32); //look NOT ok wall
    if (((bt[y][x] & 1023) >= 240) && ((bt[y][x] & 1023) < 252)) OBJcheckflags_flags &= (255 - 32); //look NOT ok cave
    if (((bt[y][x] & 1023) >= 192) && ((bt[y][x] & 1023) < 208)) OBJcheckflags_flags &= (255 - 32); //look NOT ok win


    OBJtmp = od[y][x];
OBJcf1:
    if (OBJtmp != NULL) {
        //object exists
        OBJcheckflags_td = objpassflags[(OBJtmp->type >> 10) + sprlnk[OBJtmp->type & 1023]];


        if ((OBJcheckflags_td & 1) == 0) { OBJcheckflags_flags = OBJcheckflags_flags & (255 - 1 - 2); }
        //remove bottom bit from byte value
        //*if item can be picked up include the NPCpassable flag else remove it (todo)
        //skiff and ship can go on top of chests and probably some other items too needs fixing.
        if (OBJcheckflags_td & 2) {
            OBJcheckflags_flags = OBJcheckflags_flags | 1 | 2;
            if (OBJcheckflags_flags & 4) OBJcheckflags_flags -= 4;
        } //override


        if (OBJcheckflags_td & 4) {
            OBJcheckflags_flags = OBJcheckflags_flags & (255 - 8);
            //if a bolt can't pass through it may affect our vision too
            //is it a door?
            if (((OBJtmp->type & 1023) >= 297) && ((OBJtmp->type & 1023) <= 300)) OBJcheckflags_flags &= (255 - 32);

            if ((OBJtmp->type & 1023) == 334) {
                if ((OBJtmp->type & 1024) == 0) OBJcheckflags_flags &= (255 - 32); //secret door
            }
            if ((OBJtmp->type & 1023) == 213) OBJcheckflags_flags &= (255 - 32); //mousehole
        } //remove bolt passable flag

        //make back of horse passable
        //if ((OBJtmp->type&1023)==431){
        //if ((OBJtmp->type>>10)>=8){
        //OBJcheckflags_flags|=16;
        //}
        //}

        if (OBJcheckflags_td & 8) {
            //NPC passable
            OBJcheckflags_flags |= 16;
        }

        if (OBJtmp->info & (4 + 2)) {
            //crt or npc
            if (OBJcheckflags_flags & 4) {
                //sea passable
                OBJcheckflags_flags -= 4;
            }
            if (OBJcheckflags_flags & 2) {
                //air passable
                OBJcheckflags_flags -= 2;
            }
        }


        OBJtmp = (object *) OBJtmp->next;
        goto OBJcf1;
    }

    bt[y][x] = (bt[y][x] & 1023) + OBJcheckflags_flags * 1024;
}

/**
 * @brief ROOMSYNC-P1.6: force an immediate scene resync for players inside a
 *        registered isolated room whose floor objects just changed.
 *
 * When a ground/scene object (anything the per-player sobj buffer renders --
 * dropped items, doors, signs, fields, containers) is added to / removed from
 * a tile that lies inside a registered isolated room (see gameRooms[] /
 * getroom() in function_both.cpp), every connected player whose selected
 * party member is currently inside that same room is flagged for a resync
 * (packet-35 full rebuild) on their next scene update.
 *
 * Why this exists (the "Guardian Guild basement" desync):
 *   Inside a tiny room a player who rearranges floor items with the cursor --
 *   or a stationary bystander watching someone else do it -- produces no
 *   avatar-coordinate delta, so the host's normal "only send a scene update
 *   when the player's position changed" path never fires. Synchronisation then
 *   depends entirely on the per-player sobj diff, which is evaluated behind the
 *   host-only alternating `updatemessage` frame gate and the screen+1 two-pass
 *   optimisation. That combination proved unreliable once a second player was
 *   online: floor items moved logically but kept rendering on their old tile
 *   until some unrelated event (the other player logging out, a teleport, the
 *   60 s safety heartbeat) forced a rebuild. The earlier ROOMSYNC-P1.5 change
 *   bounded the desync with a 0.5 s in-room time-based heartbeat; this drives
 *   the correction deterministically from the actual world mutation instead of
 *   a timer, so the move renders on the very next frame.
 *
 * Wire-neutral: only schedules an already-supported packet-35 resync. No wire
 * format, struct layout, or save format changes, so U6O_VERSION is NOT bumped.
 * Cheap: getroom() early-outs for the ~entire world that is not inside a room,
 * and callers gate on tclass_object[] so mover (avatar/NPC) movement -- which
 * mutates od[][] every step -- never reaches here.
 *
 * @param x World tile X that changed.
 * @param y World tile Y that changed.
 */
void roomObjectChanged(long x, long y) {
    long rx0, ry0, rx1, ry1;
    if (!getroom(x, y, &rx0, &ry0, &rx1, &ry1)) return; // not inside a room: no-op
    for (long p = 0; p <= playerlist_last; p++) {
        player *pl = playerlist[p];
        if (pl == NULL || pl->net == INVALID_NET) continue;
        object *member = pl->party[pl->selected_partymember];
        long px = member ? (long) member->x : (long) pl->px;
        long py = member ? (long) member->y : (long) pl->py;
        if (px >= rx0 && px <= rx1 && py >= ry0 && py <= ry1) pl->resync = 1;
    }
}

unsigned char OBJadd(unsigned long x, unsigned long y, object *obj) {
    if (od[y][x] == NULL) {
        od[y][x] = obj;
        obj->prev = NULL;
        obj->next = NULL;
        obj->x = x;
        obj->y = y;
    } else {
        OBJtmp = od[y][x];
    OBJadd_j1:

        //if ((objfloatflags[(OBJtmp->type>>10)+sprlnk[OBJtmp->type&1023]])&&((objfloatflags[(obj->type>>10)+sprlnk[obj->type&1023]] )==0)){
        if (objfloatflags[(OBJtmp->type >> 10) + sprlnk[OBJtmp->type & 1023]]) {
            OBJtmp2 = (object *) OBJtmp->prev;
            if (OBJtmp2 != NULL) {
                OBJtmp2->next = obj;
                obj->prev = OBJtmp2;
            } else {
                od[y][x] = obj;
                obj->prev = NULL;
            }
            obj->next = OBJtmp;
            OBJtmp->prev = obj;
            obj->x = x;
            obj->y = y;
            goto OBJaddflt1;
        }
        if (OBJtmp->next != NULL) {
            OBJtmp = (object *) OBJtmp->next;
            goto OBJadd_j1;
        }

        OBJtmp->next = obj;
        obj->prev = OBJtmp;
        obj->next = NULL;
        obj->x = x;
        obj->y = y;
    }

OBJaddflt1:
    OBJcheckflags(x, y);
    // ROOMSYNC-P1.6: a scene object just appeared on this tile -- if it is
    // inside a registered isolated room, force co-located players to resync so
    // the change renders immediately (see roomObjectChanged()). Gated on
    // tclass_object[] so mover (avatar/NPC) movement never triggers a resync.
    if (tclass_object[obj->type]) roomObjectChanged((long) x, (long) y);
    return 0; //success
}


void OBJaddtocontainer(object *container, object *objecttoadd) {
    if (obji[sprlnk[objecttoadd->type & 1023]].weight == NULL) {
        if (U6O_DEBUG) {
            static txt *errortext = txtnew();
            MessageBox(NULL, "ERROR CORRECTION: NULL WEIGHT ITEM TO PUT INTO CONTAINER PLACED ABOVE CONTAINER!",
                       "Ultima 6 Online", MB_OK);
            txtnumint(errortext, container->x);
            txtadd(errortext, "<-X CONTAINER LOCATION");
            MessageBox(NULL, errortext->d, "Ultima 6 Online", MB_OK);
            txtnumint(errortext, container->y);
            txtadd(errortext, "<-Y CONTAINER LOCATION");
            MessageBox(NULL, errortext->d, "Ultima 6 Online", MB_OK);
        }
        OBJadd(container->x, container->y, objecttoadd);
        return;
    } //weight==0
    OBJaddtocontainer_containermore = (object *) container->more;
    container->more = objecttoadd;
    objecttoadd->next = OBJaddtocontainer_containermore;
    objecttoadd->prev = container;
    if (OBJaddtocontainer_containermore) OBJaddtocontainer_containermore->prev = objecttoadd;
}

void BTset(long x, long y, unsigned short i) {
    static unsigned short p;
    x += patchx;
    y += patchy;
    bt[y][x] = i;
    if (NEThost) {
        OBJcheckflags(x, y);
        if (housenumber != 65535) {
            if ((housex1[housenumber] == 0) || (housex1[housenumber] > x)) housex1[housenumber] = x;
            if ((housex2[housenumber] == 0) || (housex2[housenumber] < x)) housex2[housenumber] = x;
            if ((housey1[housenumber] == 0) || (housey1[housenumber] > y)) housey1[housenumber] = y;
            if ((housey2[housenumber] == 0) || (housey2[housenumber] < y)) housey2[housenumber] = y;
            for (p = 0; p < housepnext[housenumber]; p++) {
                if ((x == housepx[housenumber][p]) && (y == housepy[housenumber][p])) return;
            } //p
            p = housepnext[housenumber];
            housepx[housenumber][p] = x;
            housepy[housenumber][p] = y;
            housepnext[housenumber]++;
        } //housenumber!=65535
    } //NEThost
}

