                    invobj->more2 = 1;
                }

                if (item == OBJ_TMAP) {
                    x7 = randomchestlocation(true);
                    y7 = x7 >> 10;
                    x7 = x7 & 1023;
                    x1 = rnd * 7;
                    x2 = rnd * 7;
                    while (((bt[y7 + (x2 - 3) * 2][x7 + (x1 - 3) * 2] & 1023) >= 8) && (
                               (bt[y7 + (x2 - 3) * 2][x7 + (x1 - 3) * 2] & 1023) < 16)) {
                        //check that the map marker is not in the sea.
                        x1 = rnd * 7;
                        x2 = rnd * 7;
                    }
                    x3 = rnd * 7;
                    x5 = rnd * 7;
                    invobj->more2 = x7 + 1024 * y7 + 1024 * 1024 * x1 + 1024 * 1024 * 8 * x2 + 1024 * 1024 * 8 * 8 * x3
                                    + 1024 * 1024 * 8 * 8 * 8 * x5;
                }
                if (item == 129) {
                    if ((i == 3) || (type == 362)) {
                        //CHEST ITEM/WINGED GARG SPECIAL ITEM: random food drop

                        chanceresult = rnd * 3;
