                        }
                    } else {
                        invobj->more2 = (unsigned long)(rnd * 3) + 1;
                    }
                }

                //WHAT ABOUT THE CURRENT OBJEST IN THE BAGS PREV POINTER!!!!
                invobj->info |= 112;
                invobj->next = invbag->more;
                invobj->prev = invbag;
                invbag->more = invobj;
                if (invobj->next) ((object *) invobj->next)->prev = invobj;


                // t222
                ENHANCEnewn(invobj, 8, 4);

                if (item == 42) {
