      myobj3->type=myobj2->type-1*1024; myobj3->info|=8; //<-base object
      OBJadd(x-1,y,myobj3);
      */
        }


        if (xx2 == 3) {
            //2-part creature

            xx3 = (obj->type >> 10) & 1;
            xx3++;
            if (xx3 == 2) xx3 = 0;
            //fix direction
            if (dx == -1) xx4 = 3;
            if (dx == 1) xx4 = 1;
            if (dy == -1) xx4 = 0;
            if (dy == 1) xx4 = 2;
            obj->type = xx + (xx3 << 10) + (xx4 << 11);

            //attach backside to correct position
            //get backside
            static creature *crt;
            static object *myobj;
            crt = (creature *) obj->more;
            myobj = (object *) crt->more;

            myobj->type = xx + (xx3 << 10) + (xx4 << 11) + 8 * 1024;
            OBJremove(myobj);
            OBJadd(x - dx, y - dy, myobj);


            /*
      if (obji[sprlnk[myobj2->type&1023]].v4==8){ //2-part creature
      myobj3=OBJnew(); myobj3->more=myobj2;
      myobj3->type=myobj2->type+8*1024; myobj3->info|=8; //<-base object
      OBJadd(x,y+1,myobj3);
      crt->more=myobj3;
      }
      */
        }


        if (xx2 == 1) {
            xx3 = (obj->type >> 10) & 3;

            if (xx == 363) xx3 = (obj->type >> 10) % 3; //*gargoyle

            if (obj->info & 32768) {
                //update walking position offset
                //fix pose
                //->info flag 1 is to do with walking!
                if ((xx3 == 1) && (obj->info & 1)) {
                    xx3 = 0;
                    obj->info -= 1;
                } else {
                    xx3++;
                    if (xx3 == 4) {
                        obj->info |= 1;
                        xx3 = 1;
                    }
                    if (xx3 == 3) {
                        obj->info |= 1;
                        xx3 = 1;
                    }
                }
                obj->info -= 32768;
            }

            //fix direction
            if (dx == -1) xx4 = 3;
            if (dx == 1) xx4 = 1;
            if (dy == -1) xx4 = 0;
            if (dy == 1) xx4 = 2;

            /*
      //sitting? temp fix only!
      m2obj=OBJfindlast(x,y);
      if (m2obj){
      if ((m2obj->type&1023)==252){
      xx4=(m2obj->type&3072)>>10;
      xx3=3;
      }

      if ((m2obj->type&1023)==327){
      if (((m2obj->type&3072)>>10)==2){
      xx4=(m2obj->type&3072)>>10;
      xx3=3;
      }}

      }
      */

            obj->type = xx + (xx3 << 10) + (xx4 << 12);
            if (xx == 363) obj->type = xx + (xx3 << 10) + (xx4 << 10) * 3; //*gargoyle
        } //xx2=1

        if (xx2 == 2) {
            xx3 = (obj->type >> 10) & 1;
            xx3++;
            if (xx3 == 2) xx3 = 0;
            //fix direction
            if (dx == -1) xx4 = 3;
            if (dx == 1) xx4 = 1;
            if (dy == -1) xx4 = 0;
            if (dy == 1) xx4 = 2;
            obj->type = xx + (xx3 << 10) + (xx4 << 11);
        } //xx2=2

        if (xx2 == 255) {
            //skiff
            if (dx == -1) xx4 = 3;
            if (dx == 1) xx4 = 1;
            if (dy == -1) xx4 = 0;
            if (dy == 1) xx4 = 2;
            obj->type = xx + (xx4 << 10);
        } //xx2=255


        if (xx2 == 5) {
            //mouse/rabbit
            if (dx == -1) xx4 = 3;
            if (dx == 1) xx4 = 1;
            if (dy == -1) xx4 = 0;
            if (dy == 1) xx4 = 2;
            obj->type = xx + (xx4 << 10);
        } //xx2=5


        //if (xx==412) xx2=254; //boat
        if (xx2 == 254) {
            //boat
            if (dx == -1) xx4 = 3;
            if (dx == 1) xx4 = 1;
            if (dy == -1) xx4 = 0;
            if (dy == 1) xx4 = 2;
            obj->type = xx + ((xx4 * 2 + 9) << 10);
            //add constructs

            static mlobj *mmyobj;
            if (obj->info & 2) {
                tnpc = (npc *) obj->more;
                tplayer = tnpc->player;
                mmyobj = (mlobj *) tplayer->craft_con;
            } else {
                mmyobj = (mlobj *) obj->more;
            }

            if (xx4 == 0) {
                mmyobj->obj[0]->type = obj->type - 1 * 1024;
                OBJadd(x - 1, y, mmyobj->obj[0]);
                mmyobj->obj[1]->type = obj->type - 8 * 1024;
                OBJadd(x, y - 1, mmyobj->obj[1]);
                mmyobj->obj[2]->type = obj->type - 9 * 1024;
                OBJadd(x - 1, y - 1, mmyobj->obj[2]);
                mmyobj->obj[3]->type = obj->type + 8 * 1024;
                OBJadd(x, y + 1, mmyobj->obj[3]);
                mmyobj->obj[4]->type = obj->type + 7 * 1024;
                OBJadd(x - 1, y + 1, mmyobj->obj[4]);
            }
            if (xx4 == 2) {
                mmyobj->obj[0]->type = obj->type - 1 * 1024;
                OBJadd(x - 1, y, mmyobj->obj[0]);
                mmyobj->obj[1]->type = obj->type - 8 * 1024;
                OBJadd(x, y + 1, mmyobj->obj[1]);
                mmyobj->obj[2]->type = obj->type - 9 * 1024;
                OBJadd(x - 1, y + 1, mmyobj->obj[2]);
                mmyobj->obj[3]->type = obj->type + 8 * 1024;
                OBJadd(x, y - 1, mmyobj->obj[3]);
                mmyobj->obj[4]->type = obj->type + 7 * 1024;
                OBJadd(x - 1, y - 1, mmyobj->obj[4]);
            }

            if (xx4 == 1) {
                mmyobj->obj[0]->type = obj->type - 1 * 1024;
                OBJadd(x, y - 1, mmyobj->obj[0]);
                mmyobj->obj[1]->type = obj->type - 8 * 1024;
                OBJadd(x + 1, y, mmyobj->obj[1]);
                mmyobj->obj[2]->type = obj->type - 9 * 1024;
                OBJadd(x + 1, y - 1, mmyobj->obj[2]);
                mmyobj->obj[3]->type = obj->type + 8 * 1024;
                OBJadd(x - 1, y, mmyobj->obj[3]);
                mmyobj->obj[4]->type = obj->type + 7 * 1024;
                OBJadd(x - 1, y - 1, mmyobj->obj[4]);
            }

            if (xx4 == 3) {
                mmyobj->obj[0]->type = obj->type - 1 * 1024;
                OBJadd(x, y - 1, mmyobj->obj[0]);
                mmyobj->obj[1]->type = obj->type - 8 * 1024;
                OBJadd(x - 1, y, mmyobj->obj[1]);
                mmyobj->obj[2]->type = obj->type - 9 * 1024;
                OBJadd(x - 1, y - 1, mmyobj->obj[2]);
                mmyobj->obj[3]->type = obj->type + 8 * 1024;
                OBJadd(x + 1, y, mmyobj->obj[3]);
                mmyobj->obj[4]->type = obj->type + 7 * 1024;
                OBJadd(x + 1, y - 1, mmyobj->obj[4]);
            }
        } //xx2=255

        OBJadd(x, y, obj);

        if ((obj->type & 1023) == 375) {
            //slime (combine)
            //need a grid addition array!
            /*
      ka1dosh: ok.. label each connection clockwise
      galleondragon: oh I see the pattern now
      ka1dosh: now, if it has a connection, put a 1 in that bit, if it dont, then a 0
      ka1dosh: then its binary
      galleondragon: gradually all each element and every combination of each element
      ka1dosh: least sig at the top
      u=bit 0
      r=bit 1
      d=bit 2
      l=bit 3
      connections (u,d,l,r,X)
      X
      u 0001
      r 0010
      u,r 0011
      d 0100
      u,d
      d,r
      u,d,r
      l
      u,l
      l,r
      u,l,r
      d,l
      u,d,l
      d,l,r
      u,d,l,r
      */

            xx = 0;
            if (obj2 = OBJfindlast(x, y - 1)) {
                if ((obj2->type & 1023) == 375) {
                    xx |= 1;
                    xx3 = 0;
                    if (obj3 = OBJfindlast(obj2->x, obj2->y - 1)) {
                        if ((obj3->type & 1023) == 375) xx3 |= 1;
                    }
                    if (obj3 = OBJfindlast(obj2->x + 1, obj2->y)) {
                        if ((obj3->type & 1023) == 375) xx3 |= 2;
                    }
                    if (obj3 = OBJfindlast(obj2->x, obj2->y + 1)) {
                        if ((obj3->type & 1023) == 375) xx3 |= 4;
                    }
                    if (obj3 = OBJfindlast(obj2->x - 1, obj2->y)) {
                        if ((obj3->type & 1023) == 375) xx3 |= 8;
                    }
                    obj2->type = 375 + xx3 * 1024;
                }
            }

            if (obj2 = OBJfindlast(x + 1, y)) {
                if ((obj2->type & 1023) == 375) {
                    xx |= 2;
                    xx3 = 0;
                    if (obj3 = OBJfindlast(obj2->x, obj2->y - 1)) {
                        if ((obj3->type & 1023) == 375) xx3 |= 1;
                    }
                    if (obj3 = OBJfindlast(obj2->x + 1, obj2->y)) {
                        if ((obj3->type & 1023) == 375) xx3 |= 2;
                    }
                    if (obj3 = OBJfindlast(obj2->x, obj2->y + 1)) {
                        if ((obj3->type & 1023) == 375) xx3 |= 4;
                    }
                    if (obj3 = OBJfindlast(obj2->x - 1, obj2->y)) {
                        if ((obj3->type & 1023) == 375) xx3 |= 8;
                    }
                    obj2->type = 375 + xx3 * 1024;
                }
            }

            if (obj2 = OBJfindlast(x, y + 1)) {
                if ((obj2->type & 1023) == 375) {
                    xx |= 4;
                    xx3 = 0;
                    if (obj3 = OBJfindlast(obj2->x, obj2->y - 1)) {
                        if ((obj3->type & 1023) == 375) xx3 |= 1;
                    }
                    if (obj3 = OBJfindlast(obj2->x + 1, obj2->y)) {
                        if ((obj3->type & 1023) == 375) xx3 |= 2;
                    }
                    if (obj3 = OBJfindlast(obj2->x, obj2->y + 1)) {
                        if ((obj3->type & 1023) == 375) xx3 |= 4;
                    }
                    if (obj3 = OBJfindlast(obj2->x - 1, obj2->y)) {
                        if ((obj3->type & 1023) == 375) xx3 |= 8;
                    }
                    obj2->type = 375 + xx3 * 1024;
                }
            }

            if (obj2 = OBJfindlast(x - 1, y)) {
                if ((obj2->type & 1023) == 375) {
                    xx |= 8;
                    xx3 = 0;
                    if (obj3 = OBJfindlast(obj2->x, obj2->y - 1)) {
                        if ((obj3->type & 1023) == 375) xx3 |= 1;
                    }
                    if (obj3 = OBJfindlast(obj2->x + 1, obj2->y)) {
                        if ((obj3->type & 1023) == 375) xx3 |= 2;
                    }
                    if (obj3 = OBJfindlast(obj2->x, obj2->y + 1)) {
                        if ((obj3->type & 1023) == 375) xx3 |= 4;
                    }
                    if (obj3 = OBJfindlast(obj2->x - 1, obj2->y)) {
                        if ((obj3->type & 1023) == 375) xx3 |= 8;
                    }
                    obj2->type = 375 + xx3 * 1024;
                }
            }
            obj->type = 375 + xx * 1024;
        } //slime

        return 0;
    } //walking living passable
    return 1;
}


//OBJdir changes direction of NPC/creature to face x,y
unsigned char OBJdir(object *obj, unsigned long x, unsigned long y) {
    static long dx, dy;
    static unsigned short movertype;
    static creature *crt;
    static object *obj2;

    movertype = obj->type & 1023;

    if (obji[sprlnk[movertype]].v4 == 8) {
        //two part movers (only frame change)
        if (obj->info & (2 + 4)) {
            //crt or npc
            crt = (creature *) obj->more;
            obj2 = (object *) crt->more;
            if (obj->type & 1024) {
                obj->type -= 1024;
                if (obj2->type & 1024) obj2->type -= 1024;
            } else {
                obj->type |= 1024;
                obj2->type |= 1024;
            }
        } //crt or npc
        return NULL;
    }

    if (movertype == 366) return NULL; //tanglevine tendril
    if (movertype == 365) return NULL; //tanglevine core
    if (movertype == 413) {
        //serpent
        //open & close mouth
        if (obj->type == (413 + 0 * 1024)) {
            obj->type = 413 + 14 * 1024;
            return NULL;
        }
        if (obj->type == (413 + 2 * 1024)) {
            obj->type = 413 + 15 * 1024;
            return NULL;
        }
        if (obj->type == (413 + 14 * 1024)) {
            obj->type = 413 + 0 * 1024;
            return NULL;
        }
        if (obj->type == (413 + 15 * 1024)) {
            obj->type = 413 + 2 * 1024;
            return NULL;
        }
        return NULL;
    }
    if (movertype == 347) return NULL; //reaper
    if (movertype == 343) return NULL; //insects
    if (movertype == 344) return NULL; //bat
    if (movertype == 345) return NULL; //squid
    if (movertype == 352) return NULL; //ghost
    if (movertype == 353) return NULL; //gremlin
    if (movertype == 355) return NULL; //gazer
    if (movertype == 356) return NULL; //bird
    if (movertype == 357) return NULL; //corpser
    if (movertype == 360) return NULL; //rotworms
    if (movertype == 364) return NULL; //acid slug
    if (movertype == 373) return NULL; //wisp
    if (movertype == 374) return NULL; //hydra
    if (movertype == 425) return NULL; //hydra (tenticles)
    if (movertype == 375) return NULL; //slime
    if (movertype == 391) return NULL; //hoeing farmer
    if (movertype == 415) return NULL; //raft

    //current method cannot be used if near map boundaries!
    if ((obj->x <= 1) || (obj->y <= 1) || (obj->x >= 2046) || (obj->y >= 1022)) return NULL;


    dx = 0;
    dy = 0;
    if (x > obj->x) dx = 1;
    if (x < obj->x) dx = -1;
    if (y > obj->y) dy = 1;
    if (y < obj->y) dy = -1;

    if (abs((long) (x - obj->x)) > abs((long) (y - obj->y))) dy = 0;
    else dx = 0;


    OBJmove_allow = TRUE;
    OBJmove2(obj, obj->x - dx, obj->y - dy);
    //OBJmove2(obj,obj->x-dx,obj->y-dy);
    //OBJmove2(obj,obj->x+dx*2,obj->y+dy*2);
    OBJmove2(obj, obj->x + dx, obj->y + dy);
    OBJmove_allow = FALSE;

    return NULL;

    /*
  if ((xx>=376)&&(xx<=387)) xx2=1; //fighter...woman
  if ((xx>=409)&&(xx<=410)) xx2=1; //LB+avatar
  if ((xx>=367)&&(xx<=372)) xx2=2; //demon...mongbat

  if (xx2==2){
  xx3=(obj->type>>10)&1;
  //fix direction
  if (dx==-1) xx4=3;
  if (dx==1) xx4=1;
  if (dy==-1) xx4=0;
  if (dy==1) xx4=2;
  obj->type=xx+(xx3<<10)+(xx4<<11);
  } //xx2=2
  */

    return NULL;
}


void wpf_pathfind(unsigned char *d, long sourcex, long sourcey, long destx, long desty, long maxdistance,
                  unsigned long type, unsigned long flags) {
    static long x, x2, x3, x4, y, y2, y3, y4, z, z2, z3, z4, zlooplast; //temp use variables
    static object *obj, obj2, obj3, obj4;
    static npc *tnpc, *tnpc2;
    static mlobj *mmyobj;

    wpf_nextto = WPF_NEXTTO;
    WPF_NEXTTO = 0;

    if ((flags & 8) == 0) {
        //return if dest is the same as source
        if ((destx == sourcex) && (desty == sourcey)) {
            WPF_PATHLENGTH = 0;
            WPF_RETURN = WPF_PATHFOUND;
            return;
        }
        if (wpf_nextto) {
            if ((abs(destx - sourcex) <= 1) && (abs(desty - sourcey) <= 1)) {
                WPF_PATHLENGTH = 0;
                WPF_RETURN = WPF_PATHFOUND;
                return;
            }
        } //wpf_nextto
        //return if dest is out of range of maxdistance
        x = 0;
        if (wpf_nextto) x = 1;
        if ((abs(destx - sourcex) + x) > maxdistance) {
            WPF_RETURN = WPF_NOPATHFOUND;
            return;
        }
        if ((abs(desty - sourcey) + x) > maxdistance) {
            WPF_RETURN = WPF_NOPATHFOUND;
            return;
        }
    } //(flags&8)==0

    WPF_OFFSETX = sourcex - maxdistance - 1;
    WPF_OFFSETY = sourcey - maxdistance - 1;
    z = maxdistance * 2 + 2; //array limit

    ZeroMemory(&wpf_sourcedest, sizeof(wpf_sourcedest));

    //set boundries
    for (x = 0; x <= z; x++) {
        wpf_weight[x][0] = 0;
        wpf_weight[x][z] = 0;
        wpf_weight[0][x] = 0;
        wpf_weight[z][x] = 0;
    }


    if (type == 0) {
        //type 0 setup
        wpf_npc = (npc *) WPF_OBJECT->more;
    }

    //create weightings
    for (y = 1; y < z; y++) {
        for (x = 1; x < z; x++) {
            z2 = 0; //accumulative weight
            x2 = WPF_OFFSETX + x;
            y2 = WPF_OFFSETY + y;

            if (type == 0) {
                npc *wpf_npc_tmp = (npc *)WPF_OBJECT->more;
                if (wpf_npc_tmp->player && wpf_npc_tmp->player->camera_freeze) {
                    player *p = wpf_npc_tmp->player;
                    // Frozen-camera pathfinding clamp, self-correcting: only confine
                    // paths to the frozen on-screen window while the path SOURCE is
                    // inside it. After a teleport the source jumps outside the now-stale
                    // window; clamping then would zero every tile's weight and strand
                    // the mover until the client relocks the camera. Skip in that case.
                    if (sourcex >= p->frozen_tpx && sourcex < p->frozen_tpx + p->frozen_vtx &&
                        sourcey >= p->frozen_tpy && sourcey < p->frozen_tpy + p->frozen_vty) {
                        if (x2 < p->frozen_tpx || x2 >= p->frozen_tpx + p->frozen_vtx ||
                            y2 < p->frozen_tpy || y2 >= p->frozen_tpy + p->frozen_vty) {
                            wpf_weight[x][y] = 0;
                            goto wpf_blocked;
                        }
                    }
                }
            }

            if (x2 >= 0) {
                if (y2 >= 0) {
                    if (x2 < 2048) {
                        if (y2 < 1024) {
                            //map boundries check
                            x3 = bt[y2][x2];


                            if (type == 0) {
                                z3 = 0;

                                if ((x3 & 1024) == 0) {
                                    //not land passable
                                    if ((x3 & 16384) == 0) {
                                        //not npc-swap passable
                                        wpf_weight[x][y] = 0;
                                        goto wpf_blocked;
                                    } //not npc-swap passable


                                    if (flags & 2) {
                                        //cannot swap with any npc, so this is a last resort to all alternatives!
                                        z3 = 65536;
                                        goto wpf_passcheckdone;
                                    }

                                    if (flags & 1) {
                                        if (obj = od[y2][x2]) {
                                        wpft0next:


                                            //if ((obj->type&1023)==431){
                                            //if ((obj->type>>10)>=8){
                                            //z3=16;
                                            //}
                                            //}


                                            //if ((obj->type&1023)==431){
                                            //if ((obj->type>>

                                            //}

                                            if (obj->info & 2) {
                                                tnpc = (npc *) obj->more;
                                                if (wpf_npc->player == tnpc->player) {
                                                    //wpf_weight[x][y]=0; goto wpf_blocked;
                                                    z3 = 16;
                                                } //wpf_npc->player==tnpc->player
                                            } //info&2
                                            if (obj = (object *) obj->next) goto wpft0next;
                                        } //obj
                                    } //flags&1
                                } //not land passable
                            wpf_passcheckdone:

                                /*
        OFFICIAL
        0	a place that cannot be travelled on
        3	path
        4	grass or swamp+boots
        28	tanglevine (6 extra steps to avoid)
        36	light lava,fire field,sleep field,spikes (8 steps to avoid)
        44	swamp(no boots),poison field(if not poisoned),medium lava,traps(if visible) (10 extra steps to avoid)
        52	heavy lava (12 extra steps to avoid)
        +16	partymember of same party (4 extra steps to avoid)
        */
                                x4 = x3 & 1023;
                                z2 = 4;
                                if (flags & 4) z2 = 12; //for npc scheduled pathfinding avoid non-path tiles if possible
                                if ((x4 >= 108) && (x4 <= 111)) z2 = 3;
                                if ((x4 >= 208) && (x4 <= 220)) z2 = 3;
                                if ((x4 >= 3) && (x4 <= 6)) {
                                    z2 = 44; //swamp(no boots)
                                    if (wpf_npc->boots != NULL) {
                                        if (wpf_npc->boots->type == 28) { z2 = 4; }
                                    } //swamp boots
                                }
                                if (x4 == 221) z2 = 36; //light lava
                                if (x4 == 222) z2 = 44; //medium lava
                                if (x4 == 223) z2 = 52; //heavy lava
                                if (obj = od[y2][x2]) {
                                wpft0next2:
                                    z4 = obj->type & 1023;
                                    if (z4 == 172) z2 = 36; //spikes
                                    if (z4 == 173) {
                                        //trap
                                        if (obj->info & (1 << 9)) z2 = 44;
                                    } //trap
                                    if (z4 == 317) z2 = 36; //fire field
                                    if (z4 == 318) {
                                        //poison field
                                        if ((wpf_npc->flags & 1) == 0) z2 = 44; //only if not poisoned
                                    } //318
                                    if (z4 == 320) z2 = 36; //sleep field
                                    if (z4 == 366) z2 = 28; //tendril
                                    if (obj = (object *) obj->next) goto wpft0next2;
                                } //obj
                                z2 += z3;
                            } //type==0

                            if (type == 1) {
                                //land passable
                                if (x3 & 1024) z2 = 1;
                            } //type==1

                            if (type == 2) {
                                //sea passable
                                if (x3 & 4096) z2 = 1;
                            } //type==2

                            if (type == 3) {
                                //air passable
                                if (x3 & 2048) z2 = 1;
                            } //type==3

                            if (type == 4) {
                                //ghost passable
                                if (obj = OBJfindlast(x2, y2)) {
                                    z = 1;
                                    if (obj->info & 6) z = 0;
                                }
                            }

                            if (type == 5) {
                                //tanglevine tendril passable
                                if (x3 & 1024) z = 1;
                                if (od[y2][x2]) z = 0;
                            }
                        }
                    }
                }
            } //map boundries check
            wpf_weight[x][y] = z2;
        wpf_blocked:;
        }
    } //x,y
    //wpfdebug1:

    wpf_pathfound = 0;
    wpf_lastusedn = -1;
    wpf_laststackedn = 0;
    ZeroMemory(&wpf_nweight, sizeof(wpf_nweight));

    //allow squares belonging to parts of the mover calling the pathfind to be passable
    if (obji[sprlnk[WPF_OBJECT->type & 1023]].v4 == 8) {
        //2-part mover
        obj = WPF_OBJECT;
        if (obj->info & 8) obj = (object *) obj->more; //get "head" of mover
        wpf_npc = (npc *) obj->more;
        obj = (object *) wpf_npc->more;

        //NEW GPF THIS LINE! X2!
        wpf_weight[obj->x - WPF_OFFSETX][obj->y - WPF_OFFSETY] = 1;
    } //8
    if (obji[sprlnk[WPF_OBJECT->type & 1023]].v4 == 10) {
        //silver serpent
        obj = WPF_OBJECT;
        if (obj->info & 8) obj = (object *) obj->more; //get "head" of mover
