                    } else {
                        wpf_lastusedn++;
                        wpf_nx[wpf_lastusedn] = x;
                        wpf_ny[wpf_lastusedn] = y;
                        wpf_nsource[wpf_lastusedn] = z3;
                        wpf_nweight[wpf_lastusedn] = z2 + x2;
                    }
                    wpf_sourcedest[x][y] = z3;
                    wpf_bestweight[x][y] = z2 + x2; //update array
                    if ((z2 + x2) < nextnweight) nextnweight = z2 + x2;
                } //wpf_sourcedest
            } //wpf_weight

            x -= 2;
