    //x4=rnd*4;
    x4 = rnd * 9; //make wep & armour more common
    x5 = 0;
    switch (x4) {
        //random new item type
        case 0: //any armour
        case 4:
        case 6:
        case 8:
            x4 = rnd * 25;
            if (x4 == 0) { x4 = 27; }
            break;
        case 1: //any weapon (excluding wands, staves, glass swords and rollingpins, knives etc)
        case 5:
        case 7:
            x4 = 33 + rnd * 18;
            if (x4 == 48) { x4 = 54; }
            break;
        case 2: //magic stuff (rings,wands etc)
            x4 = 78 + rnd * 8;
            if (x4 == 82) { x4 = 48; }
            if (x4 > 82) { x4 += 173; }
